// 1. MyApplication.kt - Initializes Timber and sets up global exception handling

class MyApplication : Application() {

    override fun onCreate() {
        super.onCreate()
        initLogging()
    }

    private fun initLogging() {
        if (BuildConfig.DEBUG) {
            Timber.plant(Timber.DebugTree())
        } else {
            // For production/beta, plant a custom tree to log to file or remote service
            // This FileLoggingTree is great for beta testers to capture logs
            Timber.plant(FileLoggingTree(applicationContext.filesDir))
            // You might also plant a CrashReportingTree (e.g., Firebase Crashlytics) here
            // Timber.plant(CrashReportingTree())
        }

        // Set up a default uncaught exception handler to log all crashes
        Thread.setDefaultUncaughtExceptionHandler { thread, e ->
            Timber.e(e, "Uncaught exception on thread ${thread.name}")
            // Optionally, re-throw to allow the system's default handler to show a crash dialog
            // or perform other actions like uploading crash reports.
            // If you have Crashlytics, it will typically catch this too.
            val handler = Thread.getDefaultUncaughtExceptionHandler()
            handler?.uncaughtException(thread, e)
        }
    }
}


// 2. logging/AppLogger.kt - A facade for app-specific logging events

package com.example.myapp.logging

import timber.log.Timber

object AppLogger {

    private const val TAG_AUTH = "AUTH_EVENT"
    private const val TAG_APP = "APP_EVENT"
    private const val TAG_ERROR = "APP_ERROR"

    fun logAuthSuccess(userId: String) {
        Timber.tag(TAG_AUTH).i("User authenticated successfully: %s", userId)
    }

    fun logAuthFailure(userId: String, reason: String) {
        Timber.tag(TAG_AUTH).w("User authentication failed for %s. Reason: %s", userId, reason)
    }

    fun logEvent(event: String, details: String? = null, vararg args: Any?) {
        if (details != null) {
            Timber.tag(TAG_APP).i("$event: $details", *args)
        } else {
            Timber.tag(TAG_APP).i(event, *args)
        }
    }

    fun logWarning(message: String, vararg args: Any?) {
        Timber.tag(TAG_APP).w(message, *args)
    }

    fun logError(t: Throwable? = null, message: String, vararg args: Any?) {
        if (t != null) {
            Timber.tag(TAG_ERROR).e(t, message, *args)
        } else {
            Timber.tag(TAG_ERROR).e(message, *args)
        }
    }

    fun logDebug(message: String, vararg args: Any?) {
        Timber.d(message, *args)
    }
}


