// by wrapping database calls with these logging functions.

package com.example.myapp.logging

import timber.log.Timber

object DatabaseLogger {

    private const val TAG_DB = "DATABASE_QUERY"

    fun logQuery(query: String, params: Map<String, Any?>? = null) {
        val paramString = params?.entries?.joinToString(", ") { "${it.key}=${it.value}" } ?: "No parameters"
        Timber.tag(TAG_DB).v("Executing query: '%s' with parameters: [%s]", query, paramString)
    }

    fun logInsert(table: String, values: Map<String, Any?>? = null) {
        val valueString = values?.entries?.joinToString(", ") { "${it.key}=${it.value}" } ?: "No values"
        Timber.tag(TAG_DB).v("Inserting into table '%s' with values: {%s}", table, valueString)
    }

    fun logUpdate(table: String, values: Map<String, Any?>?, whereClause: String?, whereArgs: Array<String>?) {
        val valueString = values?.entries?.joinToString(", ") { "${it.key}=${it.value}" } ?: "No values"
        val whereArgString = whereArgs?.joinToString(", ") ?: "No where args"
        Timber.tag(TAG_DB).v("Updating table '%s' with values: {%s} WHERE %s (%s)", table, valueString, whereClause, whereArgString)
    }

    fun logDelete(table: String, whereClause: String?, whereArgs: Array<String>?) {
        val whereArgString = whereArgs?.joinToString(", ") ?: "No where args"
        Timber.tag(TAG_DB).v("Deleting from table '%s' WHERE %s (%s)", table, whereClause, whereArgString)
    }

    fun logTransaction(action: String, status: String) {
        Timber.tag(TAG_DB).d("Database transaction %s: %s", action, status)
    }
}


